import React from "react";

import "./Sidebar.css";

export default function Sidebar({

activePage,

setActivePage

}) {

const menus=[

{
name:"Dashboard",
icon:"🏠"
},

{
name:"AI Assistant",
icon:"🤖"
},

{
name:"Weather",
icon:"🌦️"
},

{
name:"Crop Advisor",
icon:"🌱"
},

{
name:"Market Prices",
icon:"🛒"
},

{
name:"Schemes",
icon:"🏛️"
},

{
name:"News",
icon:"📰"
},

{
name:"Maps",
icon:"🗺️"
},

{
name:"Reports",
icon:"📊"
},

{
name:"Tasks",
icon:"📅"
},

{
name:"Finance",
icon:"💰"
},

{
name:"Farm Records",
icon:"📂"
},

{
name:"Inventory",
icon:"📦"
},

{
name:"Complaints",
icon:"📢"
},

{
name:"Calendar",
icon:"🗓️"
},

{
name:"Profile",
icon:"👨‍🌾"
},

{
name:"Settings",
icon:"⚙️"
},


];

return(

<div className="sidebar">

<div className="logo-box">

<h2>

🌾 Farmer Portal

</h2>

<p>

Digital Agriculture

</p>

</div>

<div className="menu-list">

{menus.map(item=>(

<button

key={item.name}

className={

activePage===item.name

? "menu-btn active"

: "menu-btn"

}

onClick={()=>

setActivePage(

item.name

)

}

>

<span>

{item.icon}

</span>

{item.name}

</button>

))}

</div>

<div className="help-box">

<h3>

☎️ Need Help?

</h3>

<p>

24/7 Support

</p>

<p>

1800-180-1551

</p>

</div>

</div>

);

}
